84	func profileSnapshotCacheKey(svc agentlib.FizeauService) (agentlib.FizeauService, bool) {
85		t := reflect.TypeOf(svc)
86		if t == nil || !t.Comparable() {
87			return nil, false
88		}
89		return svc, true
90	}
