99	// SelectCheapestProfile returns the lowest-power profile band that has at least
100	// one available, auto-routable model.
101	func SelectCheapestProfile(snap ProfileSnapshot) string {
102		profiles := satisfiableProfiles(snap, 0)
103		sort.SliceStable(profiles, func(i, j int) bool {
104			left, right := profiles[i], profiles[j]
105			if profileMaxForSort(left) != profileMaxForSort(right) {
106				return profileMaxForSort(left) < profileMaxForSort(right)
107			}
108			if left.MinPower != right.MinPower {
109				return left.MinPower < right.MinPower
110			}
111			return preferProfile(left, right)
112		})
113		if len(profiles) == 0 {
114			return ""
115		}
116		return profiles[0].Name
117	}
118	
119	// SelectStrongestProfile returns the highest-power profile band that has at
120	// least one available, auto-routable model.
121	func SelectStrongestProfile(snap ProfileSnapshot) string {
122		profiles := satisfiableProfiles(snap, 0)
123		sort.SliceStable(profiles, func(i, j int) bool {
124			left, right := profiles[i], profiles[j]
125			if left.MinPower != right.MinPower {
126				return left.MinPower > right.MinPower
127			}
128			if profileMaxForSort(left) != profileMaxForSort(right) {
129				return profileMaxForSort(left) > profileMaxForSort(right)
130			}
131			return preferProfile(left, right)
132		})
133		if len(profiles) == 0 {
134			return ""
135		}
136		return profiles[0].Name
137	}
138	
139	// SelectStrongestProfileAbove returns the strongest satisfiable profile whose
140	// lower bound is at least floor.
141	func SelectStrongestProfileAbove(snap ProfileSnapshot, floor int) string {
142		profiles := satisfiableProfiles(snap, floor)
143		sort.SliceStable(profiles, func(i, j int) bool {
144			left, right := profiles[i], profiles[j]
145			if left.MinPower != right.MinPower {
146				return left.MinPower > right.MinPower
147			}
148			if profileMaxForSort(left) != profileMaxForSort(right) {
149				return profileMaxForSort(left) > profileMaxForSort(right)
150			}
151			return preferProfile(left, right)
152		})
153		if len(profiles) == 0 {
154			return ""
155		}
156		return profiles[0].Name
157	}
158	
159	func satisfiableProfiles(snap ProfileSnapshot, floor int) []agentlib.ProfileInfo {
160		out := make([]agentlib.ProfileInfo, 0, len(snap.Profiles))
161		for _, profile := range snap.Profiles {
162			if profile.Name == "" || profile.Deprecated {
163				continue
164			}
165			if profile.MinPower == 0 && profile.MaxPower == 0 {
166				continue
167			}
168			if floor > 0 && profile.MinPower < floor {
169				continue
170			}
171			if profileHasAvailableModel(profile, snap.Models) {
172				out = append(out, profile)
173			}
174		}
175		return out
176	}
177	
178	func profileHasAvailableModel(profile agentlib.ProfileInfo, models []agentlib.ModelInfo) bool {
179		for _, model := range models {
180			if !model.Available || !model.AutoRoutable || model.ExactPinOnly {
181				continue
182			}
183			if profile.MinPower > 0 && model.Power < profile.MinPower {
184				continue
185			}
186			if profile.MaxPower > 0 && model.Power > profile.MaxPower {
187				continue
188			}
189			return true
190		}
191		return false
192	}
193	
194	func profileMaxForSort(profile agentlib.ProfileInfo) int {
195		if profile.MaxPower == 0 {
196			return math.MaxInt
197		}
198		return profile.MaxPower
199	}
200	
201	func preferProfile(left, right agentlib.ProfileInfo) bool {
202		leftLocal := left.ProviderPreference == "local-first"
203		rightLocal := right.ProviderPreference == "local-first"
204		if leftLocal != rightLocal {
205			return leftLocal
206		}
207		return left.Name < right.Name
208	}
