210	func selectProfileForDispatch(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, selector func(ProfileSnapshot) string) string {
211		if selector == nil || runner != nil {
212			return ""
213		}
214		selectedSvc := svc
215		if selectedSvc == nil {
216			factory := serviceRunFactory
217			if factory == nil {
218				factory = NewServiceFromWorkDir
219			}
220			built, err := factory(projectRoot)
221			if err != nil {
222				return ""
223			}
224			selectedSvc = built
225		}
226		snap, err := LoadProfileSnapshot(ctx, selectedSvc)
227		if err != nil {
228			return ""
229		}
230		return selector(snap)
231	}
