72	// runAgentViaService is the new RunAgent dispatch path that drives the
73	// agent through agentlib.FizeauService.Execute and drains the resulting event
74	// channel into a DDx Result. Old in-package code paths (RunAgent legacy
75	// loop, embeddedCompactionConfig, buildAgentProvider, findTool, and
76	// wrapProviderWithDeadlines) stay in place; this function does NOT call them.
77	//
78	// Stall detection: we delegate to the agent's StallPolicy. The agent
79	// emits a stall event then a final event with Status="stalled".
80	func runAgentViaService(r *Runner, opts RunArgs) (*Result, error) {
81		promptText, err := r.resolvePrompt(opts)
82		if err != nil {
83			return nil, err
84		}
85	
86		model := r.resolveModel(opts, "agent")
87		timeout := r.resolveTimeout(opts)
88		wallClock := r.resolveWallClock(opts)
89	
90		wd := opts.WorkDir
91		if wd == "" {
92			wd, _ = os.Getwd()
93		}
94	
95		// Construct the service. Reuses NewServiceFromWorkDir so provider/model
96		// routing data lands on the agent the same way every other DDx command
97		// constructs it (see serviceconfig.go).
98		svc, err := NewServiceFromWorkDir(wd)
99		if err != nil {
100			return nil, fmt.Errorf("agent: build service: %w", err)
101		}
102	
103		// Resolve where to write the per-request session log.
104		logDir := opts.SessionLogDir
105		if logDir == "" {
106			logDir = r.Config.SessionLogDir
107		}
108		if logDir == "" {
109			logDir = DefaultLogDir
110		}
111	
112		providerTimeout := ResolveProviderRequestTimeout(wd, opts.Provider, model, 0)
113	
114		// Build the public ExecuteRequest per CONTRACT-003.
115		req := agentlib.ServiceExecuteRequest{
116			Prompt:          promptText,
117			Model:           model,
118			Provider:        opts.Provider,
119			Harness:         "fiz",
120			ModelRef:        opts.ModelRef,
121			Reasoning:       agentlib.Reasoning(opts.Effort),
122			Permissions:     opts.Permissions,
123			WorkDir:         wd,
124			Timeout:         wallClock,
125			IdleTimeout:     timeout,
126			ProviderTimeout: providerTimeout,
127			SessionLogDir:   logDir,
128			Metadata:        metadataWithEnv(opts.Correlation, opts.Env),
129			Role:            opts.Role,
130			CorrelationID:   opts.CorrelationID,
131		}
132	
133		parentCtx := opts.Context
134		if parentCtx == nil {
135			parentCtx = context.Background()
136		}
137		ctx, cancel := context.WithCancel(parentCtx)
138		defer cancel()
139	
140		start := time.Now()
141		events, err := svc.Execute(ctx, req)
142		if err != nil {
143			return nil, fmt.Errorf("agent: execute: %w", err)
144		}
145	
146		watchdog := &drainWatchdog{
147			cancel:          cancel,
148			idleTimeout:     timeout,
149			toolCallTimeout: time.Duration(ToolCallTimeout) * time.Millisecond,
150		}
151		final, routing, _ := drainServiceEventsWithRenderer(events, nil, NewWorkLogRenderer(WorkLogRendererOptions{WorkPhase: "do"}), watchdog)
152		elapsed := time.Since(start)
153	
154		result := &Result{
155			Harness:    "fiz",
156			Model:      model,
157			DurationMS: int(elapsed.Milliseconds()),
158		}
159		if routing != nil {
160			result.Provider = routing.Provider
161			if routing.Model != "" {
162				result.Model = routing.Model
163			}
164			if routing.Harness != "" {
165				result.Harness = routing.Harness
166			}
167			if power, speed, cost, source := selectedRoutingCandidateMetrics(routing); power > 0 || speed > 0 || cost > 0 || source != "" {
168				result.PredictedPower = power
169				result.PredictedSpeedTPS = speed
170				result.PredictedCostUSDPer1kTokens = cost
171				result.PredictedCostSource = source
172			}
173		}
174		if final != nil {
175			// Normalized final text from the upstream harness (agent-32e8ff5e).
176			result.Output = final.FinalText
177			if final.Usage != nil {
178				// v0.9.1: Usage fields became *int so the API can distinguish
179				// "harness reported zero" from "harness didn't report". Treat
180				// nil as zero for DDx's int-valued result struct.
181				if final.Usage.InputTokens != nil {
182					result.InputTokens = *final.Usage.InputTokens
183				}
184				if final.Usage.OutputTokens != nil {
185					result.OutputTokens = *final.Usage.OutputTokens
186				}
187				if final.Usage.TotalTokens != nil {
188					result.Tokens = *final.Usage.TotalTokens
189				}
190			}
191			if final.CostUSD > 0 {
192				result.CostUSD = final.CostUSD
193			}
194			result.ExitCode = final.ExitCode
195			result.Error = final.Error
196			if final.RoutingActual != nil {
197				if result.Provider == "" {
198					result.Provider = final.RoutingActual.Provider
199				}
200				if final.RoutingActual.Model != "" {
201					result.Model = final.RoutingActual.Model
202				}
203				if final.RoutingActual.Harness != "" {
204					result.Harness = final.RoutingActual.Harness
205				}
206				if final.RoutingActual.Power > 0 {
207					result.ActualPower = final.RoutingActual.Power
208				}
209			}
210			if final.SessionLogPath != "" {
211				// surface as session ID for downstream cross-reference (mirrors
212				// the legacy path's AgentSessionID population).
213				result.AgentSessionID = final.SessionLogPath
214			}
215		}
216		result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
217		normalizeServiceFinalExitCode(result)
218	
219		promptSource := opts.PromptSource
220		if promptSource == "" {
221			if opts.PromptFile != "" {
222				promptSource = opts.PromptFile
223			} else {
224				promptSource = "inline"
225			}
226		}
227		r.logSession(result, len(promptText), promptText, promptSource, opts.Correlation)
228		r.recordRoutingOutcome(result, elapsed, opts)
229		return result, nil
230	}
