232	// drainServiceEvents reads service events and returns the final-event payload,
233	// the routing decision (when present in the routing_decision start event), and
234	// any canonical progress payloads emitted by the service.
235	func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
236		return drainServiceEventsWithWriter(events, nil)
237	}
238	
239	func drainServiceEventsWithWriter(events <-chan agentlib.ServiceEvent, w io.Writer) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
240		return drainServiceEventsWithRenderer(events, w, NewWorkLogRenderer(WorkLogRendererOptions{WorkPhase: "do"}), nil)
241	}
242	
243	// drainServiceEventsWithRenderer drains the event stream and returns the
244	// aggregated final/routing/progress data. When wd is non-nil it activates
245	// three wedge-prevention mechanisms:
246	//
247	//  1. Meaningful-event idle reset: the idle timer only resets on tool_call,
248	//     tool_result, and final events — not on text_delta/progress/other noise.
249	//  2. Loop detection: identical (call, result) pairs that repeat ≥4 times in
250	//     an 8-entry window trigger wd.cancel.
251	//  3. Per-tool-call timeout: a tool_call without a matching tool_result within
252	//     wd.toolCallTimeout triggers wd.cancel.
253	func drainServiceEventsWithRenderer(events <-chan agentlib.ServiceEvent, w io.Writer, renderer WorkLogRenderer, wd *drainWatchdog) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
254		var final *agentlib.ServiceFinalData
255		var routing *agentlib.ServiceRoutingDecisionData
256		var progress []agentlib.ServiceProgressData
257	
258		// Fast path: no watchdog, simple range loop with no timer overhead.
259		if wd == nil || (wd.idleTimeout == 0 && wd.toolCallTimeout == 0) {
260			for ev := range events {
261				decoded, err := agentlib.DecodeServiceEvent(ev)
262				if err != nil {
263					continue
264				}
265				switch {
266				case decoded.RoutingDecision != nil:
267					routing = decoded.RoutingDecision
268					if w != nil {
269						if line := renderer.at(ev.Time).FormatRoutingDecision(decoded.RoutingDecision); line != "" {
270							_, _ = fmt.Fprint(w, line)
271						}
272					}
273				case decoded.Progress != nil:
274					progress = append(progress, *decoded.Progress)
275					if w != nil {
276						_, _ = fmt.Fprint(w, renderer.at(ev.Time).FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
277					}
278				case decoded.Final != nil:
279					final = decoded.Final
280				}
281			}
282			return final, routing, progress
283		}
284	
285		// Watchdog path: select loop so timers can fire alongside event reads.
286		ld := &loopDetector{}
287		var pendingCall *agentlib.ServiceToolCallData
288	
289		// resetIdle stops and restarts the idle timer. Only called on meaningful events.
290		var idleTimer *time.Timer
291		var idleTimerC <-chan time.Time
292		resetIdle := func() {
293			if wd.idleTimeout <= 0 {
294				return
295			}
296			if idleTimer == nil {
297				idleTimer = time.NewTimer(wd.idleTimeout)
298				idleTimerC = idleTimer.C
299				return
300			}
301			if !idleTimer.Stop() {
302				select {
303				case <-idleTimer.C:
304				default:
305				}
306			}
307			idleTimer.Reset(wd.idleTimeout)
308		}
309	
310		var toolCallTimer *time.Timer
311		var toolCallTimerC <-chan time.Time
312		startToolCallTimer := func() {
313			if wd.toolCallTimeout <= 0 {
314				return
315			}
316			if toolCallTimer == nil {
317				toolCallTimer = time.NewTimer(wd.toolCallTimeout)
318				toolCallTimerC = toolCallTimer.C
319				return
320			}
321			if !toolCallTimer.Stop() {
322				select {
323				case <-toolCallTimer.C:
324				default:
325				}
326			}
327			toolCallTimer.Reset(wd.toolCallTimeout)
328		}
329		stopToolCallTimer := func() {
330			if toolCallTimer == nil {
331				return
332			}
333			if !toolCallTimer.Stop() {
334				select {
335				case <-toolCallTimer.C:
336				default:
337				}
338			}
339			toolCallTimerC = nil
340		}
341	
342		// Arm the idle timer immediately so a session that never starts a tool
343		// call is still bounded.
344		if wd.idleTimeout > 0 {
345			idleTimer = time.NewTimer(wd.idleTimeout)
346			idleTimerC = idleTimer.C
347		}
348		defer func() {
349			if idleTimer != nil {
350				idleTimer.Stop()
351			}
352			if toolCallTimer != nil {
353				toolCallTimer.Stop()
354			}
355		}()
356	
357		for {
358			select {
359			case ev, ok := <-events:
360				if !ok {
361					return final, routing, progress
362				}
363				decoded, err := agentlib.DecodeServiceEvent(ev)
364				if err != nil {
365					continue
366				}
367				switch {
368				case decoded.ToolCall != nil:
369					// Meaningful: tool invocation starts. Reset idle, start per-call cap.
370					resetIdle()
371					startToolCallTimer()
372					callCopy := *decoded.ToolCall
373					pendingCall = &callCopy
374	
375				case decoded.ToolResult != nil:
376					// Meaningful: tool produced a result. Stop per-call timer.
377					stopToolCallTimer()
378					if pendingCall != nil {
379						key := makeLoopKey(*pendingCall, *decoded.ToolResult)
380						if ld.record(key) {
381							_, _ = fmt.Fprintf(os.Stderr, "agent: loop detected (command=%q repeated ≥4 times): cancelling\n", pendingCall.Name)
382							if wd.cancel != nil {
383								wd.cancel()
384							}
385							return final, routing, progress
386						}
387						pendingCall = nil
388					}
389					resetIdle()
390	
391				case decoded.Final != nil:
392					// Meaningful: execution complete. Stop all timers.
393					resetIdle()
394					stopToolCallTimer()
395					final = decoded.Final
396	
397				case decoded.RoutingDecision != nil:
398					// Not a meaningful progress event: routing is a one-time setup event.
399					routing = decoded.RoutingDecision
400					if w != nil {
401						if line := renderer.at(ev.Time).FormatRoutingDecision(decoded.RoutingDecision); line != "" {
402							_, _ = fmt.Fprint(w, line)
403						}
404					}
405	
406				case decoded.Progress != nil:
407					// Not meaningful for idle reset: progress events are emitted for
408					// any tool activity including tight loops that make no real change.
409					progress = append(progress, *decoded.Progress)
410					if w != nil {
411						_, _ = fmt.Fprint(w, renderer.at(ev.Time).FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
412					}
413				}
414	
415			case <-idleTimerC:
416				_, _ = fmt.Fprintf(os.Stderr, "agent: idle timeout (%s without meaningful event): cancelling\n", wd.idleTimeout)
417				if wd.cancel != nil {
418					wd.cancel()
419				}
420				return final, routing, progress
421	
422			case <-toolCallTimerC:
423				name := ""
424				if pendingCall != nil {
425					name = pendingCall.Name
426				}
427				_, _ = fmt.Fprintf(os.Stderr, "agent: tool call timeout (%s, tool=%q): cancelling\n", wd.toolCallTimeout, name)
428				if wd.cancel != nil {
429					wd.cancel()
430				}
431				return final, routing, progress
432			}
433		}
434	}
