13	// FormatServiceProgressEntries formats canonical Fizeau progress payloads
14	// directly. It is used by callers that already have structured ServiceEvent
15	// data and should not round-trip through session-log JSONL line parsing.
16	func FormatServiceProgressEntries(entries []agentlib.ServiceProgressData) string {
17		var sb strings.Builder
18		for _, entry := range entries {
19			raw, err := json.Marshal(entry)
20			if err != nil {
21				continue
22			}
23			var data map[string]any
24			if err := json.Unmarshal(raw, &data); err != nil {
25				continue
26			}
27			if line := formatProgressLogEntry(map[string]any{
28				"type": "progress",
29				"data": data,
30			}); line != "" {
31				sb.WriteString(line)
32			}
33		}
34		return sb.String()
35	}
