63	func FormatSessionLogLines(lines string) string {
64		var entries []agentlib.ServiceProgressData
65		_ = scanJSONLReader[agentlib.ServiceProgressData](strings.NewReader(lines), func(entry agentlib.ServiceProgressData) error {
