102	func formatByteSize(bytes int) string {
103		switch {
104		case bytes <= 0:
105			return "0B"
106		case bytes < 1024:
107			return fmt.Sprintf("%dB", bytes)
108		case bytes < 1024*1024:
109			return fmt.Sprintf("%.1fKB", float64(bytes)/1024)
110		default:
111			return fmt.Sprintf("%.1fMB", float64(bytes)/(1024*1024))
