115	func encodedPayloadSize(v any) int {
116		if v == nil {
117			return 0
118		}
119		switch x := v.(type) {
120		case string:
121			return len([]byte(x))
122		case json.RawMessage:
123			return len(x)
124		case []byte:
125			return len(x)
126		default:
127			raw, err := json.Marshal(v)
128			if err != nil {
129				return 0
130			}
131			return len(raw)
132		}
