135	func formatProgressLogEntry(entry map[string]any) string {
136		data, _ := entry["data"].(map[string]any)
137		phase, _ := data["phase"].(string)
138		state, _ := data["state"].(string)
139		if line := formatStructuredProgressLine(phase, state, data); line != "" {
140			return "  " + line + "\n"
141		}
142		message, _ := data["message"].(string)
143		if message != "" {
