149	func formatStructuredProgressLine(phase, state string, data map[string]any) string {
150		switch phase {
151		case "thinking":
152			return formatThinkingProgressLine(state, data)
153		case "tool":
154			return formatToolProgressLine(state, data)
155		case "response":
156			return formatResponseProgressLine(state, data)
157		case "context":
158			return formatContextProgressLine(state, data)
159		case "compaction":
160			return formatCompactionProgressLine(state, data)
161		default:
