166	func formatThinkingProgressLine(state string, data map[string]any) string {
167		switch state {
168		case "start":
169			return "thinking ..."
170		case "update":
171			msg := progressSummaryFromData(data)
172			if msg == "" {
173				msg = "thinking update ..."
174			} else {
175				msg = "thinking update: " + msg
176			}
177			return truncateStr(msg, 120)
178		case "complete":
179			tokens := progressTokenCount(data, "output_tokens", "total_tokens", "input_tokens")
180			duration := progressDurationString(data)
181			if tokens > 0 && duration != "" {
182				return fmt.Sprintf("thinking complete %d tok in %s%s", tokens, duration, progressThroughputSuffix(data, tokens))
183			}
184			if tokens > 0 {
185				return fmt.Sprintf("thinking complete %d tok", tokens)
186			}
187			if duration != "" {
188				return fmt.Sprintf("thinking complete in %s", duration)
189			}
190			return "thinking complete"
191		default:
192			return ""
193		}
194	}
