196	func formatToolProgressLine(state string, data map[string]any) string {
197		toolName, _ := data["tool_name"].(string)
198		command, _ := data["command"].(string)
199		display := compactProgressToolDisplay(data, toolName, command, 96)
200		switch state {
201		case "start":
202			if display != "" {
203				return truncateStr("> "+display, 120)
204			}
205			return "> tool"
206		case "complete":
207			tokens := progressTokenCount(data, "total_tokens", "output_tokens", "input_tokens")
208			duration := progressDurationString(data)
209			outputSummary := progressOutputSummary(data)
210			if outputSummary != "" {
211				display = compactProgressToolDisplay(data, toolName, command, 80)
212			}
213			line := "ok"
214			if display != "" {
215				line += " " + display
216			}
217			if outputSummary != "" {
218				line += " < " + outputSummary
219			}
220			suffix := ""
221			if duration != "" {
222				suffix = " " + duration
223			}
224			if tokens > 0 {
225				suffix += fmt.Sprintf(" %dtok", tokens)
226			}
227			if throughput := progressThroughputText(data, tokens); throughput != "" {
228				if suffix != "" {
229					suffix += ", " + throughput
230				} else {
231					suffix = " " + throughput
232				}
233			}
234			return truncateStr(line, maxInt(1, 120-len(suffix))) + suffix
235		default:
236			return ""
237		}
238	}
