240	func formatTokenThroughput(tokens int, durationMS int) string {
241		if tokens <= 0 || durationMS <= 0 {
242			return ""
243		}
244		return fmt.Sprintf("%s tok/s", strconv.FormatFloat(float64(tokens)*1000/float64(durationMS), 'f', 1, 64))
245	}
