263		if data == nil {
264			return ""
265		}
266		if summary, _ := data["output_summary"].(string); strings.TrimSpace(summary) != "" {
267			return compactOutputSummaryLimit(summary, 56)
268		}
269		parts := make([]string, 0, 3)
270		if bytes := progressInt(data, "output_bytes"); bytes > 0 {
271			parts = append(parts, "out="+formatByteSize(bytes))
272		}
273		if lines := progressInt(data, "output_lines"); lines > 0 {
