366			return strings.TrimSpace(toolName)
367		}
368		command = unwrapToolCommandSummary(command)
369		command = stripShellLoginWrapper(command)
370		command = firstShellCommandSegment(command)
371		command = strings.Join(strings.Fields(command), " ")
372		fields := strings.Fields(command)
373		if len(fields) == 0 {
374			return ""
375		}
376		switch fields[0] {
377		case "sed":
378			if len(fields) >= 4 && fields[1] == "-n" {
379				return "inspect " + strings.Trim(fields[2], "'\"") + " in " + compactPathToken(fields[3], 36)
380			}
381		case "cat":
382			if len(fields) >= 2 {
383				return "inspect " + compactPathToken(fields[len(fields)-1], 36)
384			}
385		case "rg":
386			return describeRipgrepCommand(fields)
387		case "go":
388			if len(fields) >= 2 && fields[1] == "test" {
389				return "test " + strings.Join(compactPathTokens(fields[2:], 64), " ")
390			}
391		case "git":
392			return describeGitCommand(fields)
393		}
394		return compactToolDisplayLimit(toolName, command, 96)
395	}
